/** Identifier for a built-in T3 Code color theme. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/** All built-in theme identifiers, ordered for display. */
export const THEME_IDS = ["t3-light", "t3-dark", "t3-midnight"] as const satisfies readonly ThemeId[];

/** Default theme applied on first launch. */
export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

/**
 * Color values for each semantic surface in the T3 Code UI.
 * All values must be valid CSS color strings.
 */
export interface ThemeColors {
  /** Main application background surface. */
  background: string;
  /** Primary text / icon color. */
  foreground: string;
  /** Brand / interactive highlight color (maps to --primary). */
  accent: string;
  /** Navigation sidebar background. */
  sidebar: string;
  /** Code editor panel background. */
  editor: string;
  /** Integrated terminal background. */
  terminal: string;
  /** Status bar strip background. */
  statusBar: string;
}

/** A complete built-in T3 Code theme definition. */
export interface BuiltInTheme {
  readonly id: ThemeId;
  /** Human-readable display name. */
  readonly name: string;
  /**
   * Whether this theme is a dark-mode variant.
   * Controls the `dark` class on `<html>` for Tailwind `dark:` utilities.
   */
  readonly isDark: boolean;
  readonly colors: ThemeColors;
}

