      terminal: "oklch(0.072 0.024 264)",
      statusBar: "oklch(0.108 0.026 264)",
    },
  },
] as const satisfies readonly BuiltInTheme[];

/**
 * Look up a built-in theme by ID.
 * Throws if the ID is unknown — callers should only pass valid ThemeId values.
 */
export function getThemeById(id: ThemeId): BuiltInTheme {
  for (const theme of BUILT_IN_THEMES) {
