import { useCallback, useSyncExternalStore } from "react";
import { DEFAULT_THEME_ID, type ThemeId } from "@t3tools/contracts";
import { BUILT_IN_THEMES, getThemeById } from "../themes";

const STORAGE_KEY = "t3code:color-theme";
// Legacy key written by the old light/dark/system toggle — migrate on first access.
const LEGACY_STORAGE_KEY = "t3code:theme";

// ── Module-level external store ───────────────────────────────────────────────
// Kept at module scope so the theme is applied before React mounts (no flash)
// and shared across all hook instances without a Context dependency.

let listeners: Array<() => void> = [];

function emitChange(): void {
  for (const listener of listeners) listener();
}

const VALID_THEME_IDS = new Set<string>(BUILT_IN_THEMES.map((t) => t.id));

function getStored(): ThemeId {
  // Prefer the new storage key.
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw !== null && VALID_THEME_IDS.has(raw)) return raw as ThemeId;

  // Migrate from the legacy "t3code:theme" key.
  const legacy = localStorage.getItem(LEGACY_STORAGE_KEY);
  if (legacy === "light") return "t3-light";
  if (legacy === "dark") return "t3-dark";

  return DEFAULT_THEME_ID;
}

function applyTheme(themeId: ThemeId, suppressTransitions = false): void {
  const root = document.documentElement;
  if (suppressTransitions) root.classList.add("no-transitions");

  const theme = getThemeById(themeId);

  // Core semantic tokens — override the CSS-defined fallbacks.
  root.style.setProperty("--background", theme.colors.background);
  root.style.setProperty("--foreground", theme.colors.foreground);
  root.style.setProperty("--primary", theme.colors.accent);
  root.style.setProperty("--ring", theme.colors.accent);

  // Extended surface tokens (new; used by ThemeSelector preview and future surfaces).
  root.style.setProperty("--t3-sidebar", theme.colors.sidebar);
  root.style.setProperty("--t3-editor", theme.colors.editor);
  root.style.setProperty("--t3-terminal", theme.colors.terminal);
  root.style.setProperty("--t3-status-bar", theme.colors.statusBar);

  // Toggle the Tailwind `dark:` class so dark-mode variants apply correctly.
  root.classList.toggle("dark", theme.isDark);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class is effective before removal.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => root.classList.remove("no-transitions"));
  }
}

// Apply immediately at module load — before React renders — to avoid a flash.
applyTheme(getStored());

let lastSnapshot: ThemeId | null = null;

function getSnapshot(): ThemeId {
  const id = getStored();
  // Return the cached value if unchanged so useSyncExternalStore skips re-renders.
  if (lastSnapshot === id) return lastSnapshot;
  lastSnapshot = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Cross-tab sync: re-apply and re-render when another tab updates the key.
  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ── Hook ─────────────────────────────────────────────────────────────────────

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);
  const resolvedTheme: "light" | "dark" = getThemeById(theme).isDark ? "dark" : "light";

  const setTheme = useCallback((next: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  return { theme, setTheme, resolvedTheme } as const;
}

