import { CheckIcon } from "lucide-react";
import { BUILT_IN_THEMES } from "../themes";
import { useTheme } from "../hooks/useTheme";
import { cn } from "~/lib/utils";

/**
 * Theme selector with visual preview swatches for each built-in theme.
 *
 * Each card miniaturises the T3 Code layout — sidebar strip, status bar,
 * editor area, and terminal strip — using the theme's actual color values so
 * users can see exactly what they're choosing before applying it.
 */
export function ThemeSelector() {
  const { theme, setTheme } = useTheme();

  return (
    <div className="flex flex-wrap gap-4" role="radiogroup" aria-label="Color theme">
      {BUILT_IN_THEMES.map((t) => {
        const isSelected = theme === t.id;
        return (
          <button
            key={t.id}
            type="button"
            role="radio"
            aria-checked={isSelected}
            onClick={() => setTheme(t.id)}
            className={cn(
              "group relative flex flex-col items-center gap-2 rounded-xl border-2 p-2 transition-all",
              "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background",
              isSelected
                ? "border-primary shadow-sm"
                : "border-transparent hover:border-border",
            )}
          >
            {/* ── Preview swatch ────────────────────────────────────────────── */}
            <div
              className="h-16 w-24 overflow-hidden rounded-lg shadow-sm"
              aria-hidden="true"
              style={{ background: t.colors.background }}
            >
              <div className="flex h-full">
                {/* Sidebar strip */}
                <div
                  className="h-full w-5 shrink-0"
                  style={{ background: t.colors.sidebar }}
                />

                {/* Main area: status bar + editor + terminal */}
                <div className="flex flex-1 flex-col overflow-hidden">
                  {/* Status bar */}
                  <div
                    className="h-2 w-full shrink-0"
                    style={{ background: t.colors.statusBar }}
                  />

                  {/* Editor area with simulated code lines */}
                  <div
                    className="relative flex-1"
                    style={{ background: t.colors.editor }}
                  >
                    <div
                      className="absolute top-1.5 left-1.5 h-1 w-8 rounded-full opacity-80"
                      style={{ background: t.colors.accent }}
                    />
                    <div
                      className="absolute top-3.5 left-1.5 h-1 w-5 rounded-full opacity-40"
                      style={{ background: t.colors.foreground }}
                    />
                    <div
                      className="absolute top-[22px] left-1.5 h-1 w-7 rounded-full opacity-30"
                      style={{ background: t.colors.foreground }}
                    />
                  </div>

                  {/* Terminal strip */}
                  <div
                    className="h-4 w-full shrink-0"
                    style={{ background: t.colors.terminal }}
                  />
                </div>
              </div>
            </div>

            {/* ── Theme name ────────────────────────────────────────────────── */}
            <span
              className={cn(
                "text-xs font-medium transition-colors",
                isSelected
                  ? "text-foreground"
                  : "text-muted-foreground group-hover:text-foreground",
              )}
            >
              {t.name}
            </span>

            {/* ── Selected indicator ────────────────────────────────────────── */}
            {isSelected && (
              <span
                className="absolute -top-1.5 -right-1.5 flex size-5 items-center justify-center rounded-full bg-primary text-primary-foreground shadow-xs"
                aria-hidden="true"
              >
                <CheckIcon className="size-3" />
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}

